    // Now check if with this k, we can sort the array
    // To verify, we need to ensure that for every i, nums[i] can be swapped to i
    // Which means nums[i] AND i must have all bits set that are in k
    // So (nums[i] AND i) AND k == k
    // Also, the sorted array must be achievable by swapping elements under this condition
    // So we need to check if for every i, (nums[i] AND i) and k == k
    // If not, we need to reduce k by unsetting the highest bit that causes the condition to fail
    // We can do this by trying to find the maximum k where for all i, (nums[i] AND i) and k == k

    // Binary search for the maximum k
    var left = 0L
    var right = (n - 1).toLong() // maximum possible k is n-1
    var maxK = 0L
    while (left <= right) {
        val mid = (left + right) / 2
        var possible = true
        for (i in 0 until n) {
            if ((nums[i] and i.toLong() and mid) != (mid and i.toLong())) {
                possible = false
                break
            }
        }
        if (possible) {
            maxK = mid
            left = mid + 1
        } else {
            right = mid - 1
        }
    }
    return maxK
